DROP TABLE IF EXISTS `gudang_purchase_orders`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `gudang_purchase_orders` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `po_number` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `supplier_id` bigint unsigned NOT NULL,
  `date` date NOT NULL,
  `expected_date` date DEFAULT NULL,
  `status` enum('draft','sent','partial','received','cancelled') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'draft',
  `total_amount` decimal(15,2) NOT NULL DEFAULT '0.00',
  `notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `created_by` bigint unsigned NOT NULL,
  `updated_by` bigint unsigned DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `gudang_purchase_orders_po_number_unique` (`po_number`),
  KEY `gudang_purchase_orders_supplier_id_foreign` (`supplier_id`),
  KEY `gudang_purchase_orders_created_by_foreign` (`created_by`),
  KEY `gudang_purchase_orders_updated_by_foreign` (`updated_by`),
  KEY `gudang_purchase_orders_status_date_index` (`status`,`date`),
  CONSTRAINT `gudang_purchase_orders_created_by_foreign` FOREIGN KEY (`created_by`) REFERENCES `master_users` (`id`),
  CONSTRAINT `gudang_purchase_orders_supplier_id_foreign` FOREIGN KEY (`supplier_id`) REFERENCES `master_suppliers` (`id`),
  CONSTRAINT `gudang_purchase_orders_updated_by_foreign` FOREIGN KEY (`updated_by`) REFERENCES `master_users` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=165 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
