--
-- Table structure for table `gudang_receiving_details`
--

DROP TABLE IF EXISTS `gudang_receiving_details`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `gudang_receiving_details` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `receiving_id` bigint unsigned NOT NULL,
  `quantity_ordered` decimal(15,3) DEFAULT NULL,
  `product_id` bigint unsigned NOT NULL,
  `quantity` decimal(15,3) NOT NULL,
  `unit_id` bigint unsigned NOT NULL,
  `hpp_price` decimal(15,2) NOT NULL,
  `total` decimal(15,2) NOT NULL,
  `notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `kondisi` enum('baik','rusak','kurang') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `gudang_receiving_details_receiving_id_foreign` (`receiving_id`),
  KEY `gudang_receiving_details_product_id_foreign` (`product_id`),
  KEY `gudang_receiving_details_unit_id_foreign` (`unit_id`),
  CONSTRAINT `gudang_receiving_details_product_id_foreign` FOREIGN KEY (`product_id`) REFERENCES `master_products` (`id`),
  CONSTRAINT `gudang_receiving_details_receiving_id_foreign` FOREIGN KEY (`receiving_id`) REFERENCES `gudang_receivings` (`id`) ON DELETE CASCADE,
  CONSTRAINT `gudang_receiving_details_unit_id_foreign` FOREIGN KEY (`unit_id`) REFERENCES `master_units` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=2087 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

