--
-- Table structure for table `gudang_receivings`
--

DROP TABLE IF EXISTS `gudang_receivings`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `gudang_receivings` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `grn_number` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `po_id` bigint unsigned DEFAULT NULL,
  `supplier_id` bigint unsigned NOT NULL,
  `date` date NOT NULL,
  `notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `status` enum('open','closed') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'open',
  `received_by_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `supplier_rep_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `kendala` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `closed_at` timestamp NULL DEFAULT NULL,
  `closed_by` bigint unsigned DEFAULT NULL,
  `created_by` bigint unsigned NOT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `gudang_receivings_grn_number_unique` (`grn_number`),
  KEY `gudang_receivings_po_id_foreign` (`po_id`),
  KEY `gudang_receivings_supplier_id_foreign` (`supplier_id`),
  KEY `gudang_receivings_created_by_foreign` (`created_by`),
  KEY `gudang_receivings_date_index` (`date`),
  KEY `gudang_receivings_closed_by_foreign` (`closed_by`),
  CONSTRAINT `gudang_receivings_closed_by_foreign` FOREIGN KEY (`closed_by`) REFERENCES `master_users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `gudang_receivings_created_by_foreign` FOREIGN KEY (`created_by`) REFERENCES `master_users` (`id`),
  CONSTRAINT `gudang_receivings_po_id_foreign` FOREIGN KEY (`po_id`) REFERENCES `gudang_purchase_orders` (`id`) ON DELETE SET NULL,
  CONSTRAINT `gudang_receivings_supplier_id_foreign` FOREIGN KEY (`supplier_id`) REFERENCES `master_suppliers` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=168 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

