--
-- Table structure for table `gudang_return_details`
--

DROP TABLE IF EXISTS `gudang_return_details`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `gudang_return_details` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `return_id` bigint unsigned NOT NULL,
  `product_id` bigint unsigned NOT NULL,
  `quantity` decimal(15,3) NOT NULL,
  `unit_id` bigint unsigned NOT NULL,
  `received_quantity` decimal(15,3) DEFAULT NULL,
  `condition` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  PRIMARY KEY (`id`),
  KEY `gudang_return_details_return_id_foreign` (`return_id`),
  KEY `gudang_return_details_product_id_foreign` (`product_id`),
  KEY `gudang_return_details_unit_id_foreign` (`unit_id`),
  CONSTRAINT `gudang_return_details_product_id_foreign` FOREIGN KEY (`product_id`) REFERENCES `master_products` (`id`),
  CONSTRAINT `gudang_return_details_return_id_foreign` FOREIGN KEY (`return_id`) REFERENCES `gudang_returns` (`id`) ON DELETE CASCADE,
  CONSTRAINT `gudang_return_details_unit_id_foreign` FOREIGN KEY (`unit_id`) REFERENCES `master_units` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=73 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

