--
-- Table structure for table `hendhys_stock_branch`
--

DROP TABLE IF EXISTS `hendhys_stock_branch`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `hendhys_stock_branch` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `branch_id` bigint unsigned NOT NULL,
  `product_id` bigint unsigned NOT NULL,
  `quantity` decimal(15,3) NOT NULL DEFAULT '0.000',
  `quantity_return` decimal(15,3) NOT NULL DEFAULT '0.000',
  `unit_id` bigint unsigned NOT NULL,
  `last_updated` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `hendhys_stock_branch_branch_id_product_id_unique` (`branch_id`,`product_id`),
  KEY `hendhys_stock_branch_product_id_foreign` (`product_id`),
  KEY `hendhys_stock_branch_unit_id_foreign` (`unit_id`),
  CONSTRAINT `hendhys_stock_branch_branch_id_foreign` FOREIGN KEY (`branch_id`) REFERENCES `master_branches` (`id`),
  CONSTRAINT `hendhys_stock_branch_product_id_foreign` FOREIGN KEY (`product_id`) REFERENCES `master_products` (`id`),
  CONSTRAINT `hendhys_stock_branch_unit_id_foreign` FOREIGN KEY (`unit_id`) REFERENCES `master_units` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=933 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

