-- Table structure for table `hendhys_transaction_payments`
--

DROP TABLE IF EXISTS `hendhys_transaction_payments`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `hendhys_transaction_payments` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `transaction_id` bigint unsigned NOT NULL,
  `payment_method_id` bigint unsigned DEFAULT NULL,
  `payment_method` enum('cash','transfer') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `payment_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `amount` decimal(15,2) NOT NULL,
  `reference_number` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `bank_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `hendhys_transaction_payments_transaction_id_foreign` (`transaction_id`),
  KEY `hendhys_transaction_payments_payment_method_id_foreign` (`payment_method_id`),
  CONSTRAINT `hendhys_transaction_payments_payment_method_id_foreign` FOREIGN KEY (`payment_method_id`) REFERENCES `master_payment_methods` (`id`) ON DELETE SET NULL,
  CONSTRAINT `hendhys_transaction_payments_transaction_id_foreign` FOREIGN KEY (`transaction_id`) REFERENCES `hendhys_transactions` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=1343 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

