--
-- Table structure for table `hendhys_transactions`
--

DROP TABLE IF EXISTS `hendhys_transactions`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `hendhys_transactions` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `transaction_number` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `branch_id` bigint unsigned DEFAULT NULL,
  `date` date NOT NULL,
  `time` time NOT NULL,
  `customer_id` bigint unsigned DEFAULT NULL,
  `customer_name` varchar(150) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `customer_phone` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `customer_type` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'Pelanggan Individual',
  `ppn_type` enum('none','include','exclude') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'none',
  `ppn_rate` decimal(5,2) NOT NULL DEFAULT '11.00',
  `subtotal` decimal(15,2) NOT NULL DEFAULT '0.00',
  `discount_amount` decimal(15,2) NOT NULL DEFAULT '0.00',
  `tax_amount` decimal(15,2) NOT NULL DEFAULT '0.00',
  `other_costs` decimal(15,2) NOT NULL DEFAULT '0.00',
  `grand_total` decimal(15,2) NOT NULL DEFAULT '0.00',
  `status` enum('paid','pending','cancelled') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'paid',
  `notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `created_by` bigint unsigned NOT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `hendhys_transactions_transaction_number_unique` (`transaction_number`),
  KEY `hendhys_transactions_customer_id_foreign` (`customer_id`),
  KEY `hendhys_transactions_created_by_foreign` (`created_by`),
  KEY `hendhys_transactions_branch_id_date_status_index` (`branch_id`,`date`,`status`),
  CONSTRAINT `hendhys_transactions_branch_id_foreign` FOREIGN KEY (`branch_id`) REFERENCES `master_branches` (`id`) ON DELETE SET NULL,
  CONSTRAINT `hendhys_transactions_created_by_foreign` FOREIGN KEY (`created_by`) REFERENCES `master_users` (`id`),
  CONSTRAINT `hendhys_transactions_customer_id_foreign` FOREIGN KEY (`customer_id`) REFERENCES `master_customers` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=1345 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `hendhys_transactions`
--

LOCK TABLES `hendhys_transactions` WRITE;
