--
-- Table structure for table `hendhys_transfer_to_branch`
--

DROP TABLE IF EXISTS `hendhys_transfer_to_branch`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `hendhys_transfer_to_branch` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `transfer_number` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `request_id` bigint unsigned DEFAULT NULL,
  `branch_id` bigint unsigned NOT NULL,
  `date` date NOT NULL,
  `status` enum('sent','received','cancelled') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'sent',
  `notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `receive_notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `receive_photo` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `receive_kendala` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `receive_received_by_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `receive_pengirim_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_by` bigint unsigned NOT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `received_by` bigint unsigned DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `hendhys_transfer_to_branch_transfer_number_unique` (`transfer_number`),
  KEY `hendhys_transfer_to_branch_request_id_foreign` (`request_id`),
  KEY `hendhys_transfer_to_branch_created_by_foreign` (`created_by`),
  KEY `hendhys_transfer_to_branch_branch_id_date_index` (`branch_id`,`date`),
  KEY `hendhys_transfer_to_branch_received_by_foreign` (`received_by`),
  CONSTRAINT `hendhys_transfer_to_branch_branch_id_foreign` FOREIGN KEY (`branch_id`) REFERENCES `master_branches` (`id`),
  CONSTRAINT `hendhys_transfer_to_branch_created_by_foreign` FOREIGN KEY (`created_by`) REFERENCES `master_users` (`id`),
  CONSTRAINT `hendhys_transfer_to_branch_received_by_foreign` FOREIGN KEY (`received_by`) REFERENCES `master_users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `hendhys_transfer_to_branch_request_id_foreign` FOREIGN KEY (`request_id`) REFERENCES `hendhys_branch_requests` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=106 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

