--
-- Table structure for table `hendhys_transfer_to_branch_details`
--

DROP TABLE IF EXISTS `hendhys_transfer_to_branch_details`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `hendhys_transfer_to_branch_details` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `transfer_id` bigint unsigned NOT NULL,
  `product_id` bigint unsigned NOT NULL,
  `quantity` decimal(15,3) NOT NULL,
  `received_quantity` decimal(15,3) DEFAULT NULL,
  `kondisi` enum('baik','rusak','kurang') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `unit_id` bigint unsigned NOT NULL,
  PRIMARY KEY (`id`),
  KEY `hendhys_transfer_to_branch_details_transfer_id_foreign` (`transfer_id`),
  KEY `hendhys_transfer_to_branch_details_product_id_foreign` (`product_id`),
  KEY `hendhys_transfer_to_branch_details_unit_id_foreign` (`unit_id`),
  CONSTRAINT `hendhys_transfer_to_branch_details_product_id_foreign` FOREIGN KEY (`product_id`) REFERENCES `master_products` (`id`),
  CONSTRAINT `hendhys_transfer_to_branch_details_transfer_id_foreign` FOREIGN KEY (`transfer_id`) REFERENCES `hendhys_transfer_to_branch` (`id`) ON DELETE CASCADE,
  CONSTRAINT `hendhys_transfer_to_branch_details_unit_id_foreign` FOREIGN KEY (`unit_id`) REFERENCES `master_units` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=814 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

