--
-- Table structure for table `jihans_gudang_stock_movements`
--

DROP TABLE IF EXISTS `jihans_gudang_stock_movements`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `jihans_gudang_stock_movements` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `product_id` bigint unsigned NOT NULL,
  `type` enum('in','out') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `source` enum('purchase_receiving','transfer_out','return_receiving','production','adjustment') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `reference_id` bigint unsigned DEFAULT NULL,
  `quantity` decimal(15,3) NOT NULL,
  `quantity_before` decimal(15,3) NOT NULL,
  `quantity_after` decimal(15,3) NOT NULL,
  `notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `created_by` bigint unsigned DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `gudang_stock_movements_created_by_foreign` (`created_by`),
  KEY `gudang_stock_movements_product_id_type_index` (`product_id`,`type`),
  KEY `gudang_stock_movements_created_at_index` (`created_at`),
  CONSTRAINT `gudang_stock_movements_created_by_foreign` FOREIGN KEY (`created_by`) REFERENCES `master_users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `gudang_stock_movements_product_id_foreign` FOREIGN KEY (`product_id`) REFERENCES `master_products` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=3201 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

