DROP TABLE IF EXISTS `jihans_transaction_details`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `jihans_transaction_details` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `transaction_id` bigint unsigned NOT NULL,
  `product_id` bigint unsigned NOT NULL,
  `product_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `quantity` decimal(15,3) NOT NULL,
  `unit_id` bigint unsigned NOT NULL,
  `price` decimal(15,2) NOT NULL,
  `discount_percent` decimal(5,2) NOT NULL DEFAULT '0.00',
  `discount_amount` decimal(15,2) NOT NULL DEFAULT '0.00',
  `total` decimal(15,2) NOT NULL,
  PRIMARY KEY (`id`),
  KEY `jihans_transaction_details_transaction_id_foreign` (`transaction_id`),
  KEY `jihans_transaction_details_product_id_foreign` (`product_id`),
  KEY `jihans_transaction_details_unit_id_foreign` (`unit_id`),
  CONSTRAINT `jihans_transaction_details_product_id_foreign` FOREIGN KEY (`product_id`) REFERENCES `master_products` (`id`),
  CONSTRAINT `jihans_transaction_details_transaction_id_foreign` FOREIGN KEY (`transaction_id`) REFERENCES `jihans_transactions` (`id`) ON DELETE CASCADE,
  CONSTRAINT `jihans_transaction_details_unit_id_foreign` FOREIGN KEY (`unit_id`) REFERENCES `master_units` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=718 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
