DROP TABLE IF EXISTS `receipt_confirmations`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `receipt_confirmations` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `receiptable_type` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `receiptable_id` bigint unsigned NOT NULL,
  `received_by` bigint unsigned DEFAULT NULL,
  `received_at` timestamp NULL DEFAULT NULL,
  `status` enum('pending','completed','rejected') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'pending',
  `general_notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `receipt_confirmations_receiptable_type_receiptable_id_index` (`receiptable_type`,`receiptable_id`),
  KEY `receipt_confirmations_received_by_foreign` (`received_by`),
  CONSTRAINT `receipt_confirmations_received_by_foreign` FOREIGN KEY (`received_by`) REFERENCES `master_users` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=303 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

